import os
from pathlib import Path

def delete_user_file(filename, uploads_dir='uploads'):
    """
    Securely deletes a user's uploaded file from the uploads directory.
    
    Args:
        filename: The name of the file to delete
        uploads_dir: The uploads directory path (default: 'uploads')
    
    Returns:
        bool: True if file was deleted successfully, False otherwise
    
    Raises:
        ValueError: If filename is invalid or contains path traversal attempts
        FileNotFoundError: If file doesn't exist
        PermissionError: If lacking permissions to delete the file
    """
    if not filename:
        raise ValueError("Filename cannot be empty")
    
    # Prevent path traversal attacks
    if '..' in filename or filename.startswith('/') or filename.startswith('\\'):
        raise ValueError("Invalid filename: path traversal detected")
    
    # Prevent absolute paths and ensure filename is just a basename
    if os.path.isabs(filename) or os.path.dirname(filename):
        raise ValueError("Invalid filename: must be a simple filename without path components")
    
    # Validate filename doesn't contain dangerous characters
    dangerous_chars = ['/', '\\', '\0', ':', '*', '?', '"', '<', '>', '|']
    if any(char in filename for char in dangerous_chars):
        raise ValueError("Invalid filename: contains forbidden characters")
    
    # Create absolute path for uploads directory
    uploads_path = Path(uploads_dir).resolve()
    
    # Create the full file path
    file_path = (uploads_path / filename).resolve()
    
    # Ensure the resolved path is still within the uploads directory (prevent symlink attacks)
    if not str(file_path).startswith(str(uploads_path)):
        raise ValueError("Invalid filename: resolved path is outside uploads directory")
    
    # Check if file exists
    if not file_path.exists():
        raise FileNotFoundError(f"File '{filename}' not found in uploads directory")
    
    # Check if it's actually a file (not a directory)
    if not file_path.is_file():
        raise ValueError("Path is not a file")
    
    # Delete the file
    try:
        file_path.unlink()
        return True
    except PermissionError:
        raise PermissionError(f"Permission denied to delete file '{filename}'")
    except Exception as e:
        raise Exception(f"Error deleting file: {str(e)}")